              "cover_url": "https://p26-sign.douyinpic.com/tos-cn-i-dy/4a23e3ad94594545a9fd7a8db1cb716f~tplv-dy-resize-walign:360:q75.jpeg?lk3s=138a59ce&x-expires=1774753200&x-signature=ElZ%2Bq8TyG1J%2F%2Fflk6Q3HB1XB2UA%3D&from=327834062&s=PackSourceEnum_PUBLISH&se=false&sc=cover&biz_tag=aweme_video&l=20260315115820615BCEAC679E41C526B8",
